const steps = $input.all().map(item => item.json);
const body = $('Webhook').first().json.body;

let stepsText = '';
for (const s of steps) {
  stepsText += `
=== STEP ${s.step_number}: ${s.purpose} ===
Dataset: ${s.dataset_id}

${s.step_result}

`;
}

return [{
  json: {
    report_id: body.report_id,
    plan_id: '',
    email: body.email || '',
    model: body.model || 'moonshotai/kimi-k2.5',
    templateId: body.templateId || '',
    all_step_results: stepsText,
    step_count: steps.length
  }
}];

