// Get the HTML content from the Formatter agent output
// n8n agent nodes may use 'output', 'text', or 'response' depending on typeVersion
const item = $input.first().json;
let html = item.output || item.text || item.response || item.message || "";

if (typeof html !== 'string') {
  // If structured (e.g. { subject, content }), extract the HTML content
  html = html.content || html.html || JSON.stringify(html);
}

// 1. Remove newlines and carriage returns
html = html.replace(/[\n\r]/g, '');

// 2. Remove tabs and sequences of multiple spaces
html = html.replace(/\t/g, '');
html = html.replace(/\s{2,}/g, ' ');

// 3. Remove meaningless empty tags
html = html.replace(/<(span|p|div|section)>\s*<\/\1>/gi, '');

// 4. Strip stray markdown code fences
html = html.replace(/^```html|```$/g, '');

// 5. Trim
html = html.trim();

return [{
  json: {
    ...item,
    cleaned_html: html
  }
}];

